<template><div class="history-page"><section class="page-intro"><div><span>MEDICAL ARCHIVE</span><h1>历史诊疗记录</h1><p>查阅既往患者挂号与诊疗信息，快速回顾诊疗过程。</p></div><div class="archive-icon"><el-icon><FolderOpened /></el-icon></div></section><section class="overview-row"><div><span>累计记录</span><strong>{{total}}</strong><small>全部历史挂号</small></div><div><span>本页已完成</span><strong>{{completedCount}}</strong><small>已完成诊疗记录</small></div><div><span>本页已取消</span><strong>{{cancelledCount}}</strong><small>取消挂号记录</small></div></section><section class="history-card"><div class="filter-header"><div><span class="section-kicker">RECORD LIST</span><h2>诊疗档案</h2></div><div class="filters"><el-input v-model="keyword" :prefix-icon="Search" placeholder="搜索患者姓名" clearable/><el-select v-model="statusFilter" placeholder="全部状态" clearable><el-option v-for="s in statuses" :key="s" :label="s" :value="s"/></el-select><el-button :icon="Refresh" @click="loadData" :loading="loading">刷新</el-button></div></div><el-table :data="filteredList" v-loading="loading" :header-cell-style="tableHeaderStyle"><el-table-column label="患者" min-width="180"><template #default="{row}"><div class="patient"><span>{{row.patientName?.slice(0,1)}}</span><div><strong>{{row.patientName}}</strong><small>YN{{String(row.id).padStart(6,'0')}}</small></div></div></template></el-table-column><el-table-column label="就诊日期" min-width="145"><template #default="{row}"><div class="date-cell"><strong>{{row.registrationDate}}</strong><span>{{row.timeSlot}}门诊</span></div></template></el-table-column><el-table-column prop="departmentName" label="就诊科室" min-width="140"/><el-table-column label="状态" width="120"><template #default="{row}"><span class="status-pill" :class="statusClass(row.status)"><i></i>{{row.status}}</span></template></el-table-column><el-table-column label="操作" width="130" fixed="right"><template #default="{row}"><el-button class="detail-btn" size="small" @click="viewDetail(row)">查看诊疗详情 <el-icon><ArrowRight /></el-icon></el-button></template></el-table-column><template #empty><el-empty description="暂无历史诊疗记录"/></template></el-table><div class="pagination-wrap"><span>当前显示 {{filteredList.length}} 条记录</span><el-pagination v-model:current-page="page" v-model:page-size="size" :total="total" layout="total, prev, pager, next" @current-change="loadData"/></div></section></div></template>
<script setup>import{ref,computed,onMounted,watch}from'vue';import{useRouter}from'vue-router';import{Search,Refresh}from'@element-plus/icons-vue';import{getHistoryRegistrations}from'../../api/doctor';const router=useRouter(),loading=ref(false),list=ref([]),page=ref(1),size=ref(10),total=ref(0),keyword=ref(''),statusFilter=ref(''),statuses=['已就诊','已取消'];const filteredList=computed(()=>list.value);const completedCount=computed(()=>list.value.filter(r=>r.status==='已就诊').length),cancelledCount=computed(()=>list.value.filter(r=>r.status==='已取消').length);const statusClass=s=>({'已就诊':'done','已取消':'cancelled'}[s]||'');const tableHeaderStyle={background:'#f7fafb',color:'#6f858d',fontSize:'12px',fontWeight:'650',height:'48px'};const loadData=async()=>{loading.value=true;try{const r=await getHistoryRegistrations({page:page.value,size:size.value,keyword:keyword.value.trim()||undefined,status:statusFilter.value||undefined});list.value=r.data?.content||[];total.value=r.data?.totalElements||0}finally{loading.value=false}};let searchTimer;watch([keyword,statusFilter],()=>{page.value=1;clearTimeout(searchTimer);searchTimer=setTimeout(loadData,300)});const viewDetail=row=>router.push(`/consultation/${row.id}`);onMounted(loadData)</script>
<style scoped>.history-page{padding:2px}.page-intro{position:relative;overflow:hidden;display:flex;align-items:center;justify-content:space-between;min-height:130px;padding:27px 32px;border-radius:20px;background:linear-gradient(130deg,#073b5c,#087a7c);color:#fff;box-shadow:0 15px 35px rgba(10,76,90,.14)}.page-intro:after{content:'';position:absolute;width:250px;height:250px;right:-80px;top:-155px;border:1px solid rgba(255,255,255,.12);border-radius:50%;box-shadow:0 0 0 45px rgba(255,255,255,.03)}.page-intro>div{position:relative;z-index:1}.page-intro span,.section-kicker{font-size:10px;font-weight:750;letter-spacing:2px;opacity:.65}.page-intro h1{margin:7px 0 6px;font-size:25px}.page-intro p{color:rgba(255,255,255,.65);font-size:11px}.archive-icon{width:58px;height:58px;display:flex;align-items:center;justify-content:center;margin-right:25px;border:1px solid rgba(255,255,255,.16);border-radius:18px;background:rgba(255,255,255,.1);font-size:27px}.overview-row{display:grid;grid-template-columns:repeat(3,1fr);gap:16px;margin:18px 0}.overview-row>div{position:relative;padding:18px 20px;border:1px solid #e2ecee;border-radius:16px;background:#fff;box-shadow:0 7px 22px rgba(26,67,81,.05)}.overview-row>div:before{content:'';position:absolute;left:0;top:18px;bottom:18px;width:3px;border-radius:4px;background:#15a092}.overview-row span,.overview-row strong,.overview-row small{display:block}.overview-row span{color:#83969d;font-size:10px}.overview-row strong{margin:3px 0;color:#23444f;font-size:24px}.overview-row small{color:#a1afb3;font-size:9px}.history-card{overflow:hidden;border:1px solid #e1ebed;border-radius:20px;background:#fff;box-shadow:0 10px 30px rgba(26,67,81,.07)}.filter-header{display:flex;align-items:center;justify-content:space-between;gap:20px;padding:22px 25px}.section-kicker{color:#0f8c80}.filter-header h2{margin-top:4px;font-size:18px}.filters{display:flex;gap:9px}.filters .el-input{width:190px}.filters .el-select{width:125px}.filters :deep(.el-input__wrapper),.filters :deep(.el-select__wrapper){border-radius:10px;box-shadow:0 0 0 1px #dfe8ea inset}.history-card :deep(.el-table__inner-wrapper:before){display:none}.patient{display:flex;align-items:center;gap:10px}.patient>span{width:36px;height:36px;display:flex;align-items:center;justify-content:center;border-radius:11px;background:#e2f2f0;color:#087f84;font-weight:750}.patient strong,.patient small,.date-cell strong,.date-cell span{display:block}.patient strong{font-size:12px}.patient small{margin-top:3px;color:#a0adb2;font-size:9px}.date-cell strong{font-size:11px}.date-cell span{margin-top:4px;color:#8da0a6;font-size:10px}.status-pill{display:inline-flex;align-items:center;gap:6px;padding:6px 10px;border-radius:15px;font-size:10px;font-weight:650}.status-pill i{width:6px;height:6px;border-radius:50%;background:currentColor}.waiting{background:#fff3df;color:#c97819}.active{background:#e8f0ff;color:#5074ba}.done{background:#e6f7ed;color:#218c60}.cancelled{background:#fff0f0;color:#cb5b5b}.detail-btn{border-color:#d7e7e7;border-radius:9px;color:#087f84}.pagination-wrap{display:flex;align-items:center;justify-content:space-between;padding:17px 24px;border-top:1px solid #edf2f3;background:#fbfcfc}.pagination-wrap>span{color:#95a5aa;font-size:10px}@media(max-width:800px){.overview-row{grid-template-columns:1fr}.filter-header{align-items:flex-start;flex-direction:column}.filters{width:100%;flex-wrap:wrap}.filters .el-input{flex:1}.archive-icon{display:none}}</style>
